(() => {
  "use strict";

  const BUILD = "v4.1.2-smoother-player-sprite";

  const CFG = {
    worldW: 1800,
    gateX: 1690,
    groundY: 430,
    gravity: 1500,
    walk: 230,
    dash: 360,
    jump: -620,
    dashCost: 8,
    levelReach: 58,
    bossReach: 64,
    postGrace: 1.15,
    trapEscape: 5,
    trapLateEscape: 9,
    trapFirstLayerDelay: 3.0,
    trapLayerInterval: 2.0,
    trapDrain: 5,
    enemyHoldEscape: 6,
    enemyHoldDrain: 7,
    enemyHoldCooldown: 2.2,
    spawnStartX: 250,
    spawnStopBeforeGate: 260,
    spawnMin: 3.4,
    spawnMax: 5.7,
    spawnCap: 5,
    spawnAheadMin: 520,
    spawnAheadMax: 820,
    spawnOffscreenMin: 110,
    spawnOffscreenMax: 360,
    enemyRecoveryTime: 0.65,
    eliteEncounterStaminaMax: 100,
    eliteEncounterPressureMax: 100,
    defeatCycle: 2.8,
    defeatSpawn: 4.8,
    bossDamageCooldown: 2.1,
    bossContactPad: 12,
    bossAttackCooldown: 1.75,
    bossSlamTelegraph: 0.48,
    bossGlobTelegraph: 0.58,
    bossSlamActiveTime: 0.34,
    bossHealthDamage: 28,
    bossPostHitInvulnerable: 1.55,
    bossPlayerAttackCooldown: 1.1,
    bossPlayerDamage: 15,
  };

  const C = {
    sky1: "#171332", sky2: "#0f172a", back: "#1e1b4b", mid: "#312e81", near: "#111827",
    ground: "#2b1f24", groundTop: "#4b2e28", skin: "#f1bda3", hair: "#f472b6",
    hairDark: "#be185d", outfit: "#f9a8d4", outfitDark: "#831843", cape: "#111827",
    trim: "#fbbf24", magic: "#c084fc", slime: "#34d399", slimeDark: "#065f46",
    boss: "#7c3aed", bossDark: "#312e81", goblin: "#84cc16", goblinDark: "#365314",
    bat: "#7c2d12", danger: "#fb7185", white: "#e5e7eb",
  };

  const PLAYER_SPRITE_SHEETS = {
    idle: "data:image/png;base64,",
    walk: "data:image/png;base64,",
  };

  const PLAYER_SPRITE = {
    frameW: 260,
    frameH: 688,
    cols: 4,
    rows: 2,
    frames: 8,
    drawScale: 0.18,
    idleFps: 2.5,
    walkFps: 8,
  };

  const dom = {};
  const state = {
    screen: "menu",
    cam: 0,
    levelRun: false,
    bossRun: false,
    levelLast: 0,
    bossLast: 0,
    p: null,
    bp: null,
    boss: null,
    enemies: [],
    traps: [],
    pickups: [],
    encounter: null,
    defeated: false,
    defeatLoop: null,
    spawnTimer: 0,
    spawnCount: 0,
    defeatSpawnTimer: 0,
    levelInput: { left: false, right: false },
    bossInput: { left: false, right: false },
    levelAtkLock: false,
    bossAtkLock: false,
    bossPlayerAttackTimer: 0,
    bossHitCooldown: 0,
    closeEncounter: null,
    routeStats: {
      enemiesDefeated: 0,
      optionalEnemiesPassed: 0,
      bossesApproached: 0,
      bossesStruckFirst: 0,
      deepEncountersStarted: 0,
    },
    runFlags: { seenDeepEncounters: new Set() },
    sprites: {
      idle: null,
      walk: null,
      ready: false,
      failed: false,
    },
  };

  document.addEventListener("DOMContentLoaded", init);

  function init() {
    [
      "safeHub", "menu", "hub", "customize", "gallery", "game", "boss", "result",
      "hubText", "resultText", "resultStats", "levelCanvas", "bossCanvas", "armorDots",
      "levelHealth", "levelHealthFill", "levelEnergy", "levelMessage", "levelLeft", "levelRight",
      "levelJump", "levelAttack", "levelDash", "levelRestart", "bossArmorDots", "bossPlayerHealth",
      "bossPlayerHealthFill", "bossEnergy", "bossHitsLeft", "bossHealthFill", "bossMessage",
      "bossLeft", "bossRight", "bossJump", "bossAttack", "bossDash", "bossRestart",
    ].forEach((id) => { dom[id] = document.getElementById(id); });

    dom.levelCtx = dom.levelCanvas.getContext("2d");
    dom.bossCtx = dom.bossCanvas.getContext("2d");
    loadPlayerSprites();
    document.querySelectorAll("[data-build-tag]").forEach((tag) => { tag.textContent = BUILD; });

    wireNav();
    wireControls();
    preventGestures();
    restartLevel();
    showScreen("menu");
  }

  function loadPlayerSprites() {
    const idle = new Image();
    const walk = new Image();
    let loaded = 0;

    const markLoaded = () => {
      loaded += 1;
      if (loaded >= 2) state.sprites.ready = true;
    };
    const markFailed = () => { state.sprites.failed = true; };

    idle.onload = markLoaded;
    walk.onload = markLoaded;
    idle.onerror = markFailed;
    walk.onerror = markFailed;
    idle.src = PLAYER_SPRITE_SHEETS.idle;
    walk.src = PLAYER_SPRITE_SHEETS.walk;

    state.sprites.idle = idle;
    state.sprites.walk = walk;
  }

  function wireNav() {
    document.addEventListener("click", (event) => {
      const go = event.target?.dataset?.go;
      if (go) showScreen(go);
    });
    dom.safeHub.addEventListener("click", () => showScreen("hub"));
    dom.levelRestart.addEventListener("click", restartLevel);
    dom.bossRestart.addEventListener("click", startBoss);
  }

  function wireControls() {
    bindHold(dom.levelLeft, () => levelHold("left", true), () => levelHold("left", false));
    bindHold(dom.levelRight, () => levelHold("right", true), () => levelHold("right", false));
    bindPress(dom.levelJump, () => levelAction("jump"));
    bindPress(dom.levelAttack, () => levelAction("attack"));
    bindPress(dom.levelDash, () => levelAction("dash"));

    bindHold(dom.bossLeft, () => { state.bossInput.left = true; }, () => { state.bossInput.left = false; });
    bindHold(dom.bossRight, () => { state.bossInput.right = true; }, () => { state.bossInput.right = false; });
    bindPress(dom.bossJump, () => jump(state.bp));
    bindPress(dom.bossAttack, bossAttack);
    bindPress(dom.bossDash, () => dash(state.bp, setBossMessage, updateBossHud));
  }

  function bindPress(button, fn) {
    let active = false;
    button.addEventListener("pointerdown", (event) => {
      event.preventDefault();
      if (active) return;
      active = true;
      fn();
      button.blur();
    });
    const up = (event) => { event.preventDefault(); active = false; button.blur(); };
    button.addEventListener("pointerup", up);
    button.addEventListener("pointercancel", up);
    button.addEventListener("pointerleave", up);
  }

  function bindHold(button, down, upFn) {
    let active = false;
    button.addEventListener("pointerdown", (event) => {
      event.preventDefault();
      if (active) return;
      active = true;
      down();
      button.blur();
    });
    const up = (event) => {
      event.preventDefault();
      if (!active) return;
      active = false;
      upFn();
      button.blur();
    };
    button.addEventListener("pointerup", up);
    button.addEventListener("pointercancel", up);
    button.addEventListener("pointerleave", up);
  }

  function preventGestures() {
    document.addEventListener("touchmove", (event) => event.preventDefault(), { passive: false });
    ["contextmenu", "selectstart", "dragstart", "gesturestart"].forEach((type) => {
      document.addEventListener(type, (event) => event.preventDefault());
    });
  }

  function showScreen(id) {
    document.querySelectorAll(".screen").forEach((screen) => screen.classList.remove("is-active"));
    (dom[id] || dom.hub).classList.add("is-active");
    state.screen = id;
    state.levelRun = false;
    state.bossRun = false;
    state.levelInput.left = false;
    state.levelInput.right = false;
    state.bossInput.left = false;
    state.bossInput.right = false;
    if (id === "game") startLevel();
    if (id === "boss") startBoss();
    window.scrollTo(0, 0);
  }

  function makePlayer(overrides = {}) {
    return {
      x: 70, y: 344, w: 38, h: 82, vx: 0, vy: 0, face: 1, renderFace: 1, onGround: false,
      armor: 3, health: 100, energy: 0, attackFlash: 0, invulnerable: 0,
      dashing: 0, intangible: 0, gateReached: false, ...overrides,
    };
  }

  function makeEnemy(kind, x, y, w, h, hp, opt = {}) {
    return {
      kind, x, y, w, h, hp, maxHp: hp, dir: opt.dir || -1, flying: !!opt.flying,
      jumpy: !!opt.jumpy, spawned: !!opt.spawned, homeX: opt.homeX ?? x,
      patrolMin: opt.patrolMin, patrolMax: opt.patrolMax, zoneMin: opt.zoneMin,
      zoneMax: opt.zoneMax, dormant: !!opt.dormant, holdCooldown: 0, recover: 0, t: 0,
    };
  }

  function makeTrap(x, y) {
    return { x, y, w: 92, h: 25, active: false, used: false, t: 0 };
  }

  function restartLevel() {
    state.levelAtkLock = false;
    state.encounter = null;
    state.defeated = false;
    state.defeatLoop = null;
    state.cam = 0;
    state.spawnTimer = 2.8;
    state.spawnCount = 0;
    state.defeatSpawnTimer = CFG.defeatSpawn;
    state.levelInput.left = false;
    state.levelInput.right = false;
    state.p = makePlayer();
    state.enemies = [
      makeEnemy("slime", 500, 396, 38, 34, 1, { jumpy: true }),
      makeEnemy("goblin", 930, 382, 50, 48, 2),
      makeEnemy("bat", 1240, 250, 46, 34, 2, { flying: true }),
      makeEnemy("slime", 790, 396, 38, 34, 1, { jumpy: true, dormant: true, zoneMin: 585, zoneMax: 885, patrolMin: 700, patrolMax: 910 }),
      makeEnemy("goblin", 1370, 382, 50, 48, 2, { dormant: true, zoneMin: 1120, zoneMax: 1460, patrolMin: 1260, patrolMax: 1500 }),
    ];
    state.traps = [makeTrap(690, 405), makeTrap(1120, 405)];
    state.pickups = [{ x: 720, y: 330, collected: false }, { x: 1420, y: 320, collected: false }];
    setLevelMessage("Reference core: advance carefully toward the gate");
    updateLevelHud();
    drawLevel(0);
  }

  function startLevel() {
    restartLevel();
    state.levelRun = true;
    state.levelLast = performance.now();
    requestAnimationFrame(levelLoop);
  }

  function startBoss() {
    const source = state.p || makePlayer({ energy: 20 });
    state.bossAtkLock = false;
    state.bossHitCooldown = 0;
    state.bp = makePlayer({ x: 110, armor: Math.max(3, source.armor), health: source.health, energy: Math.max(20, source.energy) });
    state.boss = {
      x: 670, y: 326, w: 120, h: 104, hp: 100, maxHp: 100, hitFlash: 0,
      cooldown: 0.65, windup: 0, telegraph: 0, telegraphType: "",
      lastAttackType: "glob", projectiles: [], defeated: false, engaged: false, openedBy: "",
    };
    setBossMessage(`Build ${BUILD}`);
    updateBossHud();
    drawBoss(0);
    state.bossRun = true;
    state.bossLast = performance.now();
    requestAnimationFrame(bossLoop);
  }

  function setLevelMessage(text) { dom.levelMessage.textContent = text; }
  function setBossMessage(text) { dom.bossMessage.textContent = text; }

  function armorDots(count) {
    return [1, 2, 3].map((i) => `<i class="dot ${i <= count ? "" : "is-empty"}"></i>`).join("");
  }

  function updateLevelHud() {
    const p = state.p;
    dom.armorDots.innerHTML = armorDots(p.armor);
    dom.levelHealth.textContent = Math.max(0, Math.ceil(p.health));
    dom.levelHealthFill.style.width = `${clamp(p.health, 0, 100)}%`;
    dom.levelEnergy.textContent = Math.floor(p.energy);
    updateDashButton(dom.levelDash, p.energy);
  }

  function updateBossHud() {
    const p = state.bp;
    const b = state.boss;
    dom.bossArmorDots.innerHTML = armorDots(p.armor);
    dom.bossPlayerHealth.textContent = Math.max(0, Math.ceil(p.health));
    dom.bossPlayerHealthFill.style.width = `${clamp(p.health, 0, 100)}%`;
    dom.bossEnergy.textContent = Math.floor(p.energy);
    dom.bossHitsLeft.textContent = Math.max(0, Math.ceil(b.hp / CFG.bossPlayerDamage));
    dom.bossHealthFill.style.width = `${clamp(b.hp, 0, 100)}%`;
    updateDashButton(dom.bossDash, p.energy);
  }

  function updateDashButton(button, energy) {
    button.classList.toggle("is-locked", energy < CFG.dashCost);
    button.disabled = false;
  }

  function levelHold(dir, value) {
    if (state.defeated) return;
    if (state.encounter && value) { struggle(); return; }
    state.levelInput[dir] = value;
  }

  function levelAction(action) {
    if (state.defeated) return;
    if (state.encounter) { struggle(); return; }
    if (action === "jump") jump(state.p);
    if (action === "attack") levelAttack();
    if (action === "dash") dash(state.p, setLevelMessage, updateLevelHud);
  }

  function jump(p) {
    if (!p || !p.onGround) return;
    if (p === state.bp && state.boss?.defeated) return;
    p.vy = CFG.jump;
    p.onGround = false;
  }

  function dash(p, msg, hud) {
    if (!p || p.energy < CFG.dashCost) return;
    if (p === state.bp && state.boss?.defeated) return;
    p.energy -= CFG.dashCost;
    p.dashing = 0.42;
    p.invulnerable = 0.8;
    p.intangible = 0.95;
    p.vx = CFG.dash * p.face;
    msg("Intangible");
    hud();
  }

  function levelAttack() {
    const p = state.p;
    if (!p || state.levelAtkLock || state.defeated) return;
    state.levelAtkLock = true;
    setTimeout(() => { state.levelAtkLock = false; }, 120);
    p.attackFlash = 0.14;
    p.energy = Math.min(100, p.energy + 4);
    const target = nearestEnemy(attackBox(p, CFG.levelReach), state.enemies, p);
    if (target) {
      target.hp -= 1;
      p.energy = Math.min(100, p.energy + 16);
      if (target.hp <= 0) state.routeStats.enemiesDefeated += 1;
      setLevelMessage(target.hp <= 0 ? "Enemy down" : `${target.kind} HP ${target.hp}/${target.maxHp}`);
    } else setLevelMessage("Miss");
    updateLevelHud();
  }

  function bossAttack() {
    const p = state.bp;
    const b = state.boss;
    if (!p || !b || b.hp <= 0 || b.defeated) return;
    if (!b.engaged) {
      b.engaged = true;
      b.openedBy = "strike";
      state.routeStats.bossesStruckFirst += 1;
    }
    if (state.bossPlayerAttackTimer > 0) {
      setBossMessage(`Recovering ${(state.bossPlayerAttackTimer).toFixed(1)}s`);
      return;
    }
    state.bossPlayerAttackTimer = CFG.bossPlayerAttackCooldown;
    p.attackFlash = Math.min(0.42, CFG.bossPlayerAttackCooldown * 0.45);
    p.energy = Math.min(100, p.energy + 4);
    if (rectsOverlap(attackBox(p, CFG.bossReach), b)) {
      b.hp = Math.max(0, b.hp - CFG.bossPlayerDamage);
      b.hitFlash = 0.22;
      p.energy = Math.min(100, p.energy + 14);
      setBossMessage(b.hp > 0 ? `King Slime: ${Math.ceil(b.hp / CFG.bossPlayerDamage)} strong hits left` : "King Slime defeated");
      updateBossHud();
      if (b.hp <= 0) finishBoss();
    } else {
      setBossMessage("Miss");
      updateBossHud();
    }
  }

  function finishBoss() {
    const p = state.bp;
    state.boss.hp = 0;
    state.bossRun = false;
    updateBossHud();
    dom.hubText.textContent = "Level 1 clear: King Slime defeated.";
    dom.resultText.textContent = "King Slime defeated. Forest route cleared.";
    dom.resultStats.textContent = `Remaining health: ${Math.max(0, Math.ceil(p.health))} | Armor layers: ${p.armor} | Energy: ${Math.floor(p.energy)} | Route: ${state.routeStats.bossesStruckFirst ? "strike-first" : "standard"}`;
    setTimeout(() => showScreen("result"), 800);
  }

  function attackBox(actor, reach) {
    return { x: actor.face > 0 ? actor.x + actor.w : actor.x - reach, y: actor.y + 10, w: reach, h: 44 };
  }

  function nearestEnemy(hitbox, enemies, p) {
    let best = null;
    let bestDist = Infinity;
    enemies.forEach((enemy) => {
      if (enemy.hp <= 0 || enemy.dormant || !rectsOverlap(hitbox, enemy)) return;
      const d = Math.abs(centerX(p) - centerX(enemy));
      if (d < bestDist) { bestDist = d; best = enemy; }
    });
    return best;
  }

  function canHazardHit(actor) {
    return actor && actor.invulnerable <= 0 && actor.dashing <= 0 && actor.intangible <= 0 && !state.encounter && !state.defeated;
  }

  function canBossHazardHit(actor) {
    return actor && state.bossHitCooldown <= 0 && actor.invulnerable <= 0 && actor.dashing <= 0 && actor.intangible <= 0;
  }

  function handleEnemyContact(enemy) {
    const p = state.p;
    if (!canHazardHit(p) || enemy.dormant || enemy.recover > 0) return;
    if (p.armor > 0) {
      hurtLevelPlayer(enemy.flying);
      enemy.holdCooldown = CFG.enemyHoldCooldown;
      return;
    }
    if (enemy.holdCooldown > 0) return;
    startEnemyHold(enemy);
  }

  function hurtLevelPlayer(ignoreArmor) {
    const p = state.p;
    if (!canHazardHit(p)) return;
    p.invulnerable = 1;
    p.energy = Math.min(100, p.energy + 12);
    if (p.armor > 0 && !ignoreArmor) {
      p.armor -= 1;
      setLevelMessage("Layer hit — stay mobile");
    } else {
      p.health -= 25;
      setLevelMessage("Health-state damage");
    }
    if (p.health <= 0) {
      p.health = 0;
      updateLevelHud();
      enterDefeatLoop(null);
      return;
    }
    updateLevelHud();
  }

  function hurtBossPlayer(ignoreArmor) {
    const p = state.bp;
    if (!canBossHazardHit(p)) return;
    state.bossHitCooldown = CFG.bossDamageCooldown;
    p.invulnerable = CFG.bossPostHitInvulnerable;
    p.energy = Math.min(100, p.energy + 12);
    if (p.armor > 0 && !ignoreArmor) {
      p.armor -= 1;
      setBossMessage(`Armor layer hit (${p.armor}/3 left)`);
    } else {
      p.health -= CFG.bossHealthDamage;
      setBossMessage(`Health hit -${CFG.bossHealthDamage}`);
    }
    if (p.health <= 0) {
      p.health = 0;
      state.boss.defeated = true;
      state.boss.projectiles = [];
      setBossMessage("Boss defeat placeholder - Restart Boss or Hub");
    }
    updateBossHud();
  }

  function updateActor(actor, input, dt, maxX) {
    actor.attackFlash = Math.max(0, actor.attackFlash - dt);
    actor.invulnerable = Math.max(0, actor.invulnerable - dt);
    actor.dashing = Math.max(0, actor.dashing - dt);
    actor.intangible = Math.max(0, actor.intangible - dt);
    const axis = Number(input.right) - Number(input.left);
    if (axis) {
      actor.face = axis;
      actor.renderFace = axis;
      actor.vx = axis * (actor.dashing > 0 ? CFG.dash : CFG.walk);
    } else if (actor.dashing <= 0) actor.vx *= 0.82;
    actor.vy += CFG.gravity * dt;
    actor.x += actor.vx * dt;
    actor.y += actor.vy * dt;
    if (actor.y + actor.h >= CFG.groundY) {
      actor.y = CFG.groundY - actor.h;
      actor.vy = 0;
      actor.onGround = true;
    } else actor.onGround = false;
    actor.x = clamp(actor.x, 20, maxX);
  }

  function updateLevel(dt) {
    const p = state.p;
    if (state.defeated) {
      updateDefeatField(dt);
      state.cam = clamp(p.x - 330, 0, CFG.worldW - 960);
      return;
    }
    if (state.encounter) {
      updateEncounter(dt);
      state.cam = clamp(p.x - 330, 0, CFG.worldW - 960);
      return;
    }

    updateActor(p, state.levelInput, dt, CFG.worldW - 80);
    state.cam = clamp(p.x - 330, 0, CFG.worldW - 960);
    activateZones();

    state.traps.forEach((trap) => {
      trap.t += dt;
      if (!trap.used && rectsOverlap(p, trap) && canHazardHit(p)) startTrapEncounter(trap);
    });

    state.enemies.forEach((enemy) => {
      if (enemy.hp <= 0 || enemy.dormant) return;
      updateEnemy(enemy, dt);
      if (rectsOverlap(p, enemy)) handleEnemyContact(enemy);
    });

    state.pickups.forEach((pickup) => {
      if (pickup.collected) return;
      if (distance(p.x + p.w / 2, p.y + p.h / 2, pickup.x, pickup.y) < 42) {
        pickup.collected = true;
        p.energy = Math.min(100, p.energy + 25);
        setLevelMessage("Pickup");
        updateLevelHud();
      }
    });

    updateSpawnDirector(dt);

    if (p.x > CFG.gateX && !p.gateReached) {
      p.gateReached = true;
      setLevelMessage("Boss gate reached");
      setTimeout(() => showScreen("boss"), 450);
    }
  }

  function activateZones() {
    const p = state.p;
    state.enemies.forEach((enemy) => {
      if (!enemy.dormant) return;
      if (p.x >= enemy.zoneMin && p.x <= enemy.zoneMax) {
        enemy.dormant = false;
        setLevelMessage("Nearby enemies stir");
      }
    });
  }

  function updateSpawnDirector(dt) {
    const p = state.p;
    if (!p || state.encounter) return;
    if (!state.defeated) {
      if (p.x < CFG.spawnStartX) return;
      if (p.x > CFG.gateX - CFG.spawnStopBeforeGate) return;
    }
    const active = state.enemies.filter((enemy) => enemy.hp > 0 && !enemy.dormant).length;
    if (active >= CFG.spawnCap) return;
    state.spawnTimer -= dt;
    if (state.spawnTimer > 0) return;
    spawnEnemyAhead();
    state.spawnTimer = randomRange(CFG.spawnMin, CFG.spawnMax);
  }

  function spawnEnemyAhead() {
    const p = state.p;
    const cameraRight = state.cam + 960;
    const offscreenX = cameraRight + randomRange(CFG.spawnOffscreenMin, CFG.spawnOffscreenMax);
    const playerAheadX = p.x + randomRange(CFG.spawnAheadMin, CFG.spawnAheadMax);
    const spawnX = clamp(Math.max(offscreenX, playerAheadX), p.x + 280, CFG.gateX - 180);
    const patrolMin = Math.max(260, spawnX - 170);
    const patrolMax = Math.min(CFG.gateX - 120, spawnX + 160);
    const roll = Math.random();
    let enemy;
    if (roll < 0.45) enemy = makeEnemy("slime", spawnX, 396, 38, 34, 1, { jumpy: true, spawned: true, patrolMin, patrolMax });
    else if (roll < 0.78) enemy = makeEnemy("goblin", spawnX, 382, 50, 48, 2, { spawned: true, patrolMin, patrolMax });
    else enemy = makeEnemy("bat", spawnX, 250, 46, 34, 2, { flying: true, spawned: true, patrolMin, patrolMax });
    state.spawnCount += 1;
    state.enemies.push(enemy);
    if (!state.defeated) setLevelMessage(`Enemy pressure ${state.spawnCount}`);
  }

  function updateEnemy(enemy, dt) {
    enemy.t += dt;
    enemy.holdCooldown = Math.max(0, enemy.holdCooldown - dt);
    enemy.recover = Math.max(0, enemy.recover - dt);
    if (enemy.recover > 0 && !state.defeated) {
      if (!enemy.flying) enemy.y = CFG.groundY - enemy.h;
      return;
    }
    if (state.defeated && state.defeatLoop?.source === enemy) {
      enemy.x += (centerX(state.p) - centerX(enemy)) * 0.9 * dt;
      enemy.y = enemy.flying ? 245 + Math.sin(enemy.t * 3) * 28 : CFG.groundY - enemy.h;
      return;
    }
    if (enemy.flying) {
      const minX = enemy.patrolMin ?? 1150;
      const maxX = enemy.patrolMax ?? 1440;
      enemy.x += enemy.dir * 82 * dt;
      enemy.y = 245 + Math.sin(enemy.t * 3) * 38;
      if (enemy.x < minX || enemy.x > maxX) enemy.dir *= -1;
      return;
    }
    if (enemy.jumpy) {
      const minX = enemy.patrolMin ?? 390;
      const maxX = enemy.patrolMax ?? 760;
      enemy.x += enemy.dir * 58 * dt;
      enemy.y = CFG.groundY - enemy.h - Math.abs(Math.sin(enemy.t * 4.8)) * 42;
      if (enemy.x < minX || enemy.x > maxX) enemy.dir *= -1;
      return;
    }
    const minX = enemy.patrolMin ?? 840;
    const maxX = enemy.patrolMax ?? 1080;
    enemy.x += enemy.dir * 65 * dt;
    enemy.y = CFG.groundY - enemy.h;
    if (enemy.x < minX || enemy.x > maxX) enemy.dir *= -1;
  }

  function startTrapEncounter(trap) {
    const p = state.p;
    trap.active = true;
    p.vx = 0; p.vy = 0; p.dashing = 0; p.intangible = 0; p.invulnerable = 0;
    p.x = clamp(trap.x + trap.w / 2 - p.w / 2, 20, CFG.worldW - 80);
    p.y = CFG.groundY - p.h;
    state.levelInput.left = false;
    state.levelInput.right = false;
    state.encounter = {
      type: "trap", phase: "escape", source: trap, progress: 0, required: CFG.trapEscape,
      layerTimer: CFG.trapFirstLayerDelay, layerInterval: CFG.trapLayerInterval, drain: CFG.trapDrain,
    };
    setLevelMessage("Root snare — tap Jump / Atk / Dash to escape");
    updateLevelHud();
  }

  function startEnemyHold(enemy) {
    const p = state.p;
    p.vx = 0; p.vy = 0; p.dashing = 0; p.intangible = 0; p.invulnerable = 0;
    p.y = CFG.groundY - p.h;
    enemy.holdCooldown = CFG.enemyHoldCooldown;
    enemy.x = p.x + (p.face > 0 ? p.w - 6 : -enemy.w + 6);
    enemy.y = enemy.flying ? p.y + 16 : CFG.groundY - enemy.h;
    state.levelInput.left = false;
    state.levelInput.right = false;
    state.encounter = {
      type: "enemy", phase: "hold", source: enemy, progress: 0,
      required: CFG.enemyHoldEscape, drain: CFG.enemyHoldDrain,
    };
    setLevelMessage(`${enemy.kind} health-state hold — mash to recover`);
    updateLevelHud();
  }

  function struggle() {
    const e = state.encounter;
    if (!e) return;
    e.progress = Math.min(e.required, e.progress + 1);
    if (e.type === "trap" && e.phase === "escape") setLevelMessage(`Escaping root: ${e.progress}/${e.required}`);
    else if (e.type === "trap") setLevelMessage(`Breaking late hold: ${e.progress}/${e.required}`);
    else setLevelMessage(`Recovering: ${e.progress}/${e.required}`);
    if (e.progress >= e.required) escapeEncounter();
  }

  function updateEncounter(dt) {
    const e = state.encounter;
    const p = state.p;
    if (!e) return;
    p.vx = 0; p.vy = 0; p.dashing = 0; p.intangible = 0; p.invulnerable = 0;
    p.y = CFG.groundY - p.h;
    if (e.type === "trap") updateTrapEncounter(e, p, dt);
    else updateEnemyEncounter(e, p, dt);
  }

  function updateTrapEncounter(e, p, dt) {
    if (e.phase === "escape") {
      e.layerTimer -= dt;
      if (e.layerTimer <= 0) {
        if (p.armor > 0) {
          p.armor -= 1;
          updateLevelHud();
          setLevelMessage(p.armor > 0 ? "Root removed one layer — keep tapping" : "Late hold triggered — still mash");
        }
        if (p.armor <= 0) {
          e.phase = "late";
          e.progress = 0;
          e.required = CFG.trapLateEscape;
          setLevelMessage("Late hold placeholder — mash to break out");
          updateLevelHud();
          return;
        }
        e.layerTimer += e.layerInterval;
      }
    }
    if (e.phase === "late") {
      p.health = Math.max(0, p.health - e.drain * dt);
      updateLevelHud();
      if (p.health <= 0) enterDefeatLoop(e.source);
    }
  }

  function updateEnemyEncounter(e, p, dt) {
    const enemy = e.source;
    if (enemy && enemy.hp > 0) {
      enemy.x = p.x + (p.face > 0 ? p.w - 6 : -enemy.w + 6);
      enemy.y = enemy.flying ? p.y + 16 : CFG.groundY - enemy.h;
    }
    p.health = Math.max(0, p.health - e.drain * dt);
    updateLevelHud();
    if (p.health <= 0) enterDefeatLoop(enemy);
  }

  function escapeEncounter() {
    const e = state.encounter;
    if (!e) return;
    const p = state.p;
    if (e.type === "trap") {
      const trap = e.source;
      trap.used = true;
      trap.active = false;
      p.x = clamp(trap.x + trap.w + 30, 20, CFG.worldW - 80);
      setLevelMessage("Escaped — root disabled");
    } else {
      const enemy = e.source;
      if (enemy) {
        enemy.holdCooldown = CFG.enemyHoldCooldown;
        enemy.recover = CFG.enemyRecoveryTime;
        enemy.x += p.face > 0 ? 70 : -70;
      }
      p.x = clamp(p.x - p.face * 26, 20, CFG.worldW - 80);
      setLevelMessage("Recovered — move");
    }
    state.encounter = null;
    p.invulnerable = CFG.postGrace;
    p.intangible = CFG.postGrace;
    p.dashing = 0;
    p.vx = 0;
    p.vy = 0;
    p.y = CFG.groundY - p.h;
    p.energy = Math.min(100, p.energy + 10);
    updateLevelHud();
  }

  function enterDefeatLoop(source) {
    const p = state.p;
    state.encounter = null;
    state.defeated = true;
    state.levelInput.left = false;
    state.levelInput.right = false;
    p.health = 0;
    p.vx = 0; p.vy = 0; p.dashing = 0; p.intangible = 0; p.invulnerable = 0;
    p.y = CFG.groundY - p.h;
    state.defeatLoop = {
      source: source && source.hp > 0 ? source : chooseDefeatEnemy(),
      timer: CFG.defeatCycle,
      cycle: 1,
    };
    setLevelMessage("Defeat loop placeholder — Restart or Hub");
    updateLevelHud();
  }

  function updateDefeatField(dt) {
    const p = state.p;
    p.vx = 0; p.vy = 0; p.dashing = 0; p.intangible = 0; p.invulnerable = 0;
    p.y = CFG.groundY - p.h;
    state.enemies.forEach((enemy) => { if (enemy.hp > 0 && !enemy.dormant) updateEnemy(enemy, dt); });
    state.defeatSpawnTimer -= dt;
    if (state.defeatSpawnTimer <= 0) {
      updateSpawnDirector(CFG.spawnMax);
      state.defeatSpawnTimer = CFG.defeatSpawn;
    }
    if (!state.defeatLoop) state.defeatLoop = { source: chooseDefeatEnemy(), timer: CFG.defeatCycle, cycle: 1 };
    state.defeatLoop.timer -= dt;
    if (state.defeatLoop.timer <= 0) {
      state.defeatLoop.source = chooseDefeatEnemy();
      state.defeatLoop.timer = CFG.defeatCycle;
      state.defeatLoop.cycle += 1;
      setLevelMessage(`Defeat loop placeholder ${state.defeatLoop.cycle} — Restart or Hub`);
    }
  }

  function chooseDefeatEnemy() {
    const p = state.p;
    const active = state.enemies.filter((enemy) => enemy.hp > 0 && !enemy.dormant);
    if (!active.length) return null;
    active.sort((a, b) => Math.abs(centerX(a) - centerX(p)) - Math.abs(centerX(b) - centerX(p)));
    return active[0];
  }

  function canStartDeepEncounter(encounterId) {
    return encounterId && !state.runFlags.seenDeepEncounters.has(encounterId);
  }

  function markDeepEncounter(encounterId) {
    if (!encounterId) return;
    state.runFlags.seenDeepEncounters.add(encounterId);
    state.routeStats.deepEncountersStarted += 1;
  }

  function startCloseEncounterFramework(encounterId, sourceLabel, opening = "contact") {
    if (!canStartDeepEncounter(encounterId)) return false;
    markDeepEncounter(encounterId);
    state.closeEncounter = {
      active: true,
      id: encounterId,
      sourceLabel,
      opening,
      phase: "intro",
      stamina: CFG.eliteEncounterStaminaMax,
      pressure: 0,
      cycle: 1,
      result: "pending",
    };
    return true;
  }

  function resolveCloseEncounterPlaceholder(result = "escape") {
    if (!state.closeEncounter) return;
    state.closeEncounter.result = result;
    state.closeEncounter.active = false;
  }

  function updateBoss(dt) {
    const p = state.bp;
    const b = state.boss;
    if (b.defeated) return;
    state.bossHitCooldown = Math.max(0, state.bossHitCooldown - dt);
    updateActor(p, state.bossInput, dt, 820);
    b.hitFlash = Math.max(0, b.hitFlash - dt);
    b.cooldown -= dt;
    b.windup = Math.max(0, b.windup - dt);
    if (b.telegraph > 0) {
      b.telegraph -= dt;
      if (b.telegraph <= 0) releaseBossAttack();
    }
    b.x += Math.sign(centerX(p) - centerX(b)) * 36 * dt;
    b.x = clamp(b.x, 520, 820);
    if (b.cooldown <= 0 && b.telegraph <= 0 && b.windup <= 0) {
      b.cooldown = CFG.bossAttackCooldown;
      beginBossAttack();
    }
    if (b.windup > 0 && canBossHazardHit(p) && rectsOverlap(bossPlayerHitbox(p), bossSlamZone())) hurtBossPlayer(false);
    b.projectiles.forEach((proj) => updateProjectile(proj, p, dt));
    b.projectiles = b.projectiles.filter((proj) => proj.life > 0 && proj.x > -80 && proj.x < 1040);
    if (canBossHazardHit(p) && rectsOverlap(bossPlayerHitbox(p), b)) {
      if (!b.engaged) {
        b.engaged = true;
        b.openedBy = "contact";
        state.routeStats.bossesApproached += 1;
      }
      hurtBossPlayer(false);
    }
  }

  function beginBossAttack() {
    const p = state.bp;
    const b = state.boss;
    const glob = Math.abs(centerX(p) - centerX(b)) > 215 || b.lastAttackType === "slam";
    b.telegraph = glob ? CFG.bossGlobTelegraph : CFG.bossSlamTelegraph;
    b.telegraphType = glob ? "glob" : "slam";
    b.lastAttackType = b.telegraphType;
    setBossMessage(glob ? "King Slime forms a glob" : "King Slime swells up");
  }

  function releaseBossAttack() {
    const p = state.bp;
    const b = state.boss;
    if (b.telegraphType === "slam") b.windup = CFG.bossSlamActiveTime;
    if (b.telegraphType === "glob") {
      const dir = centerX(p) < centerX(b) ? -1 : 1;
      b.projectiles.push({ x: b.x + b.w / 2, y: b.y + 50, w: 28, h: 28, vx: dir * 290, life: 2.8, ignoreUntilClear: false });
    }
    b.telegraphType = "";
  }

  function updateProjectile(proj, p, dt) {
    proj.x += proj.vx * dt;
    proj.life -= dt;
    const touching = rectsOverlap(bossPlayerHitbox(p), proj);
    if (!touching) { proj.ignoreUntilClear = false; return; }
    if (!canBossHazardHit(p)) { proj.ignoreUntilClear = true; return; }
    if (proj.ignoreUntilClear) return;
    proj.life = 0;
    hurtBossPlayer(false);
  }

  function bossPlayerHitbox(p) {
    const pad = CFG.bossContactPad;
    return {
      x: p.x + pad,
      y: p.y + 8,
      w: Math.max(12, p.w - pad * 2),
      h: Math.max(20, p.h - 14),
    };
  }

  function bossSlamZone() {
    const b = state.boss;
    return { x: b.x - 74, y: b.y + 18, w: b.w + 148, h: 82 };
  }

  function levelLoop(now) {
    if (!state.levelRun) return;
    const dt = Math.min(0.033, (now - state.levelLast) / 1000);
    state.levelLast = now;
    updateLevel(dt);
    drawLevel(now / 1000);
    requestAnimationFrame(levelLoop);
  }

  function bossLoop(now) {
    if (!state.bossRun) return;
    const dt = Math.min(0.033, (now - state.bossLast) / 1000);
    state.bossLast = now;
    updateBoss(dt);
    drawBoss(now / 1000);
    requestAnimationFrame(bossLoop);
  }

  function drawLevel(time) {
    const ctx = dom.levelCtx;
    const cam = state.cam;
    clearArena(ctx);
    drawForest(ctx, cam, time);
    drawGround(ctx, -cam, CFG.worldW);
    drawTraps(ctx, cam, time);
    drawGate(ctx, cam, time);
    drawPickups(ctx, cam, time);
    drawEnemies(ctx, cam, time);
    drawAttackFlash(ctx, state.p, CFG.levelReach, cam);
    drawWitch(ctx, state.p, cam, time, state.defeated);
    drawTrapWrap(ctx, state.p, cam, time);
    drawDefeatLoop(ctx, cam, time);
    drawHitbox(ctx, state.p, cam);
    drawEncounterOverlay(ctx);
  }

  function drawBoss(time) {
    const ctx = dom.bossCtx;
    const b = state.boss;
    clearArena(ctx);
    drawForest(ctx, 0, time);
    drawGround(ctx, 0, 960);
    if (!b.defeated) {
      if (b.telegraph > 0 && b.telegraphType === "slam") drawSlamWarning(ctx, bossSlamZone(), time);
      if (b.windup > 0) drawSlamActive(ctx, bossSlamZone(), time);
      if (b.telegraph > 0 && b.telegraphType === "glob") drawGlobCharge(ctx, b, time);
      b.projectiles.forEach((proj) => drawProjectile(ctx, proj, time));
      drawKingSlime(ctx, b, time);
      drawAttackFlash(ctx, state.bp, CFG.bossReach, 0);
      drawWitch(ctx, state.bp, 0, time, false);
      drawHitbox(ctx, state.bp, 0);
    } else {
      drawKingSlime(ctx, b, time);
      drawWitch(ctx, state.bp, 0, time, true);
      drawBossDefeatOverlay(ctx);
    }
    ctx.fillStyle = C.white;
    ctx.font = "16px system-ui";
    ctx.fillText(`King Slime hits left: ${Math.max(0, Math.ceil(b.hp / CFG.bossPlayerDamage))}`, 20, 34);
  }

  function clearArena(ctx) {
    const g = ctx.createLinearGradient(0, 0, 0, 430);
    g.addColorStop(0, C.sky1);
    g.addColorStop(1, C.sky2);
    ctx.clearRect(0, 0, 960, 540);
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, 960, 540);
  }

  function drawForest(ctx, cam, time) {
    drawTreeLayer(ctx, cam * 0.16, 72, C.back, 0.8);
    drawTreeLayer(ctx, cam * 0.32, 132, C.mid, 0.58);
    drawTreeLayer(ctx, cam * 0.52, 196, C.near, 0.74);
    ctx.fillStyle = "rgba(251,191,36,.18)";
    for (let i = 0; i < 12; i += 1) {
      const x = ((i * 93 - cam * 0.22 + Math.sin(time + i) * 8) % 1040) - 40;
      const y = 120 + ((i * 41) % 210);
      ctx.fillRect(x, y, 3, 3);
    }
  }

  function drawTreeLayer(ctx, cam, baseY, color, alpha) {
    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.fillStyle = color;
    for (let x = -120; x < 1100; x += 96) {
      const dx = x - (cam % 96);
      const h = 210 + ((x * 7) % 70);
      ctx.fillRect(dx + 38, baseY + 160 - h, 20, h);
      ctx.beginPath();
      ctx.moveTo(dx - 12, baseY + 160 - h + 65);
      ctx.lineTo(dx + 48, baseY + 160 - h - 30);
      ctx.lineTo(dx + 110, baseY + 160 - h + 65);
      ctx.closePath();
      ctx.fill();
    }
    ctx.restore();
  }

  function drawGround(ctx, offsetX, width) {
    ctx.fillStyle = C.ground;
    ctx.fillRect(offsetX, CFG.groundY, width, 110);
    ctx.fillStyle = C.groundTop;
    ctx.fillRect(offsetX, CFG.groundY, width, 10);
    ctx.fillStyle = "rgba(34,197,94,.18)";
    for (let x = 0; x < width; x += 50) ctx.fillRect(offsetX + x, CFG.groundY - 2, 26, 3);
  }

  function drawTraps(ctx, cam, time) {
    state.traps.forEach((trap) => {
      const x = trap.x - cam;
      ctx.save();
      ctx.globalAlpha = trap.used ? 0.22 : 1;
      ctx.fillStyle = trap.active ? "rgba(244,114,182,.45)" : "rgba(52,211,153,.28)";
      ctx.beginPath();
      ctx.ellipse(x + trap.w / 2, trap.y + trap.h / 2, trap.w / 2, trap.h / 2 + Math.sin(time * 5 + trap.x) * 2, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = trap.used ? "rgba(148,163,184,.55)" : "rgba(209,250,229,.65)";
      ctx.lineWidth = 3;
      for (let i = 0; i < 4; i += 1) {
        ctx.beginPath();
        ctx.moveTo(x + 12 + i * 20, trap.y + 18);
        ctx.quadraticCurveTo(x + 8 + i * 24, trap.y - 12 - Math.sin(time * 6 + i) * 8, x + 22 + i * 20, trap.y + 8);
        ctx.stroke();
      }
      ctx.restore();
    });
  }

  function drawGate(ctx, cam, time) {
    const x = CFG.gateX - cam;
    ctx.save();
    ctx.translate(x + 24, 378);
    ctx.fillStyle = "rgba(192,132,252,.15)";
    ctx.beginPath();
    ctx.ellipse(0, 4, 48 + Math.sin(time * 4) * 3, 78, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = "#6b21a8";
    ctx.fillRect(-22, -50, 44, 100);
    ctx.fillStyle = "#f9a8d4";
    ctx.fillRect(-13, -39, 26, 78);
    ctx.restore();
  }

  function drawPickups(ctx, cam, time) {
    state.pickups.forEach((p) => {
      if (p.collected) return;
      ctx.save();
      ctx.translate(p.x - cam, p.y + Math.sin(time * 5) * 4);
      ctx.fillStyle = "rgba(192,132,252,.20)";
      ctx.beginPath(); ctx.arc(0, 0, 24, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = C.magic;
      ctx.beginPath();
      ctx.moveTo(0, -16); ctx.lineTo(13, 0); ctx.lineTo(0, 16); ctx.lineTo(-13, 0);
      ctx.closePath(); ctx.fill();
      ctx.restore();
    });
  }

  function drawEnemies(ctx, cam, time) {
    state.enemies.forEach((e) => {
      if (e.hp <= 0 || e.dormant) return;
      if (e.kind === "slime") drawSlime(ctx, e, cam);
      if (e.kind === "goblin") drawGoblin(ctx, e, cam, time);
      if (e.kind === "bat") drawBat(ctx, e, cam, time);
      ctx.fillStyle = "#fff";
      ctx.font = "12px system-ui";
      ctx.fillText(String(e.hp), e.x - cam + e.w / 2 - 3, e.y - 7);
    });
  }

  function drawSlime(ctx, e, cam) {
    const x = e.x - cam + e.w / 2;
    const y = e.y + e.h;
    const squash = 1 + Math.abs(Math.sin(e.t * 4.8)) * 0.18;
    ctx.save(); ctx.translate(x, y); ctx.scale(1.12 / squash, squash);
    ctx.fillStyle = C.slimeDark;
    ctx.beginPath(); ctx.ellipse(0, -16, 21, 18, 0, Math.PI, 0); ctx.lineTo(21, 0); ctx.quadraticCurveTo(0, 12, -21, 0); ctx.closePath(); ctx.fill();
    ctx.fillStyle = C.slime;
    ctx.beginPath(); ctx.ellipse(0, -17, 16, 12, 0, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = "#d1fae5"; ctx.fillRect(-7, -20, 4, 4); ctx.fillRect(5, -20, 4, 4);
    ctx.restore();
  }

  function drawGoblin(ctx, e, cam, time) {
    const x = e.x - cam + e.w / 2;
    const y = e.y + e.h;
    const stride = Math.sin(time * 10) * 4;
    ctx.save(); ctx.translate(x, y); ctx.scale(e.dir > 0 ? 1 : -1, 1);
    ctx.fillStyle = C.goblinDark; ctx.fillRect(-12, -28, 8, 28 + stride); ctx.fillRect(5, -28, 8, 28 - stride);
    ctx.fillStyle = C.goblin; ctx.fillRect(-18, -58, 36, 32);
    ctx.fillStyle = "#a3e635"; ctx.beginPath(); ctx.ellipse(0, -70, 17, 14, 0, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = "#0f172a"; ctx.fillRect(4, -73, 4, 4);
    ctx.fillStyle = "#78350f"; ctx.fillRect(14, -44, 28, 8);
    ctx.restore();
  }

  function drawBat(ctx, e, cam, time) {
    const x = e.x - cam + e.w / 2;
    const y = e.y + e.h / 2;
    const flap = Math.sin(time * 15) * 13;
    ctx.save(); ctx.translate(x, y); ctx.scale(e.dir > 0 ? 1 : -1, 1);
    ctx.fillStyle = "rgba(124,45,18,.6)";
    ctx.beginPath(); ctx.moveTo(-8, 1); ctx.quadraticCurveTo(-42, -24 - flap, -38, 20); ctx.lineTo(-9, 13); ctx.closePath(); ctx.fill();
    ctx.beginPath(); ctx.moveTo(8, 1); ctx.quadraticCurveTo(42, -24 + flap, 38, 20); ctx.lineTo(9, 13); ctx.closePath(); ctx.fill();
    ctx.fillStyle = C.bat; ctx.beginPath(); ctx.ellipse(0, 0, 15, 12, 0, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = C.white; ctx.fillRect(-5, -3, 4, 4); ctx.fillRect(4, -3, 4, 4);
    ctx.restore();
  }

  function drawAttackFlash(ctx, actor, reach, cam) {
    if (!actor || actor.attackFlash <= 0) return;
    const box = attackBox(actor, reach);
    ctx.save(); ctx.globalAlpha = 0.65; ctx.fillStyle = C.trim;
    ctx.beginPath(); ctx.ellipse(box.x - cam + reach / 2, box.y + 18, reach * 0.58, 26, actor.face > 0 ? -0.25 : 0.25, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
  }

  function drawPlayerSprite(ctx, p, cam, time, fallen) {
    if (!state.sprites.ready || state.sprites.failed) return false;

    const moving = Math.abs(p.vx) > 70 && p.onGround && !fallen;
    const sheet = moving ? state.sprites.walk : state.sprites.idle;
    const fps = moving ? PLAYER_SPRITE.walkFps : PLAYER_SPRITE.idleFps;
    const frame = Math.floor(time * fps) % PLAYER_SPRITE.frames;
    const sx = (frame % PLAYER_SPRITE.cols) * PLAYER_SPRITE.frameW;
    const sy = Math.floor(frame / PLAYER_SPRITE.cols) * PLAYER_SPRITE.frameH;
    const drawW = PLAYER_SPRITE.frameW * PLAYER_SPRITE.drawScale;
    const drawH = PLAYER_SPRITE.frameH * PLAYER_SPRITE.drawScale;
    const cx = p.x - cam + p.w / 2;
    const footY = p.y + p.h + 4;

    const flicker = (p.invulnerable > 0 || p.dashing > 0 || p.intangible > 0) && Math.floor(Date.now() / 70) % 2;

    const face = p.renderFace || p.face || 1;

    ctx.save();
    if (p.dashing > 0 && !fallen) {
      ctx.globalAlpha = 0.18;
      for (let i = 1; i <= 3; i += 1) {
        ctx.save();
        ctx.translate(cx - face * i * 14, footY + i * 5);
        ctx.scale(face, 1);
        ctx.drawImage(sheet, sx, sy, PLAYER_SPRITE.frameW, PLAYER_SPRITE.frameH, -drawW / 2, -drawH, drawW, drawH);
        ctx.restore();
      }
    }
    ctx.globalAlpha = flicker ? 0.62 : 1;
    ctx.translate(cx, footY);
    ctx.scale(face, 1);
    if (fallen) ctx.rotate(-0.45);
    ctx.drawImage(sheet, sx, sy, PLAYER_SPRITE.frameW, PLAYER_SPRITE.frameH, -drawW / 2, -drawH, drawW, drawH);
    ctx.restore();

    return true;
  }

  function drawWitch(ctx, p, cam, time, fallen) {
    if (!p) return;
    if (drawPlayerSprite(ctx, p, cam, time, fallen)) return;
    const cx = p.x - cam + p.w / 2;
    const footY = p.y + p.h;
    const flicker = (p.invulnerable > 0 || p.dashing > 0 || p.intangible > 0) && Math.floor(Date.now() / 70) % 2;
    const bob = p.onGround ? Math.sin(time * 10) * Math.min(1, Math.abs(p.vx) / CFG.walk) * 2 : -2;
    ctx.save(); ctx.translate(cx, footY + bob); ctx.scale(p.face, 1);
    if (fallen) ctx.rotate(-0.45);
    if (p.dashing > 0) {
      ctx.fillStyle = "rgba(244,114,182,.18)";
      for (let i = 1; i <= 3; i += 1) ctx.fillRect(-21 - i * 13, -70 + i * 5, 22, 55 - i * 7);
    }
    ctx.globalAlpha = flicker ? 0.62 : 1;
    drawCape(ctx, p, time); drawLegs(ctx, p, time); drawBody(ctx, p); drawArms(ctx, p); drawHead(ctx, time); drawHat(ctx, time);
    ctx.restore();
  }

  function drawCape(ctx, p, time) {
    const flutter = Math.sin(time * 6) * 3;
    ctx.fillStyle = C.cape;
    ctx.beginPath(); ctx.moveTo(-20, -70); ctx.quadraticCurveTo(-34, -42, -28, -14 + flutter); ctx.lineTo(20, -16); ctx.lineTo(18, -70); ctx.closePath(); ctx.fill();
    if (p.armor >= 2) {
      ctx.fillStyle = C.hair;
      ctx.beginPath(); ctx.moveTo(-16, -66); ctx.quadraticCurveTo(-26, -40, -21, -20 + flutter); ctx.lineTo(12, -19); ctx.lineTo(11, -66); ctx.closePath(); ctx.fill();
    }
  }

  function drawLegs(ctx, p, time) {
    const stride = p.onGround ? Math.sin(time * 12) * Math.min(1, Math.abs(p.vx) / CFG.walk) * 5 : 2;
    ctx.fillStyle = C.skin; ctx.fillRect(-12, -36, 9, 24 + stride); ctx.fillRect(5, -36, 9, 24 - stride);
    ctx.fillStyle = "#0f172a"; ctx.fillRect(-14, -17 + stride, 13, 19); ctx.fillRect(4, -17 - stride, 13, 19);
  }

  function drawBody(ctx, p) {
    ctx.fillStyle = p.armor > 0 ? C.outfit : "#d8b4fe";
    ctx.beginPath(); ctx.moveTo(-16, -73); ctx.lineTo(16, -73); ctx.lineTo(20, -32); ctx.lineTo(9, -24); ctx.lineTo(-9, -24); ctx.lineTo(-20, -32); ctx.closePath(); ctx.fill();
    ctx.fillStyle = C.outfitDark; ctx.fillRect(-16, -52, 32, 8);
    if (p.armor >= 3) { ctx.fillStyle = C.trim; ctx.fillRect(-17, -73, 34, 4); ctx.fillRect(-2, -69, 4, 36); }
  }

  function drawArms(ctx, p) {
    const lift = p.attackFlash > 0 ? -16 : 0;
    ctx.fillStyle = C.skin; ctx.fillRect(-26, -64, 9, 28); ctx.fillRect(17, -64 + lift, 9, 28);
    ctx.fillStyle = C.outfitDark; ctx.fillRect(20, -39 + lift, 15, 6);
  }

  function drawHead(ctx, time) {
    ctx.fillStyle = C.skin; ctx.beginPath(); ctx.arc(0, -90, 15, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = C.hair; ctx.beginPath(); ctx.ellipse(-2, -96, 20, 16, -0.22, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = C.hairDark; ctx.beginPath(); ctx.ellipse(-14, -78 + Math.sin(time * 5) * 1.5, 8, 22, 0.2, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = "#0f172a"; ctx.fillRect(5, -92, 3, 3);
  }

  function drawHat(ctx, time) {
    ctx.fillStyle = C.cape; ctx.beginPath(); ctx.ellipse(0, -104, 32, 7, 0, 0, Math.PI * 2); ctx.fill();
    ctx.beginPath(); ctx.moveTo(-16, -105); ctx.quadraticCurveTo(-3, -144 + Math.sin(time * 2) * 1.5, 16, -107); ctx.closePath(); ctx.fill();
    ctx.fillStyle = C.hair; ctx.fillRect(-15, -108, 30, 5);
  }

  function drawTrapWrap(ctx, p, cam, time) {
    const e = state.encounter;
    if (!e || !p) return;
    const x = p.x - cam + p.w / 2;
    const y = p.y + p.h;
    ctx.save(); ctx.strokeStyle = e.type === "enemy" ? "rgba(244,114,182,.9)" : "rgba(52,211,153,.9)"; ctx.lineWidth = 5;
    for (let i = 0; i < 5; i += 1) {
      ctx.beginPath(); ctx.moveTo(x - 36 + i * 18, y + 2); ctx.quadraticCurveTo(x - 28 + i * 12, y - 42 - Math.sin(time * 7 + i) * 8, x - 18 + i * 9, y - 24); ctx.stroke();
    }
    ctx.restore();
  }

  function drawDefeatLoop(ctx, cam, time) {
    if (!state.defeated) return;
    const p = state.p;
    const enemy = state.defeatLoop?.source;
    ctx.save();
    ctx.fillStyle = "rgba(15,23,42,.35)"; ctx.fillRect(0, 0, 960, 540);
    ctx.fillStyle = "rgba(244,114,182,.24)"; ctx.beginPath(); ctx.ellipse(p.x - cam + p.w / 2, p.y + p.h - 18, 70 + Math.sin(time * 4) * 5, 34, 0, 0, Math.PI * 2); ctx.fill();
    if (enemy) {
      ctx.strokeStyle = "rgba(255,255,255,.55)"; ctx.lineWidth = 2; ctx.strokeRect(enemy.x - cam - 4, enemy.y - 4, enemy.w + 8, enemy.h + 8);
      ctx.fillStyle = C.white; ctx.font = "13px system-ui"; ctx.fillText("active loop", enemy.x - cam - 10, enemy.y - 10);
    }
    ctx.restore();
  }

  function drawEncounterOverlay(ctx) {
    const e = state.encounter;
    if (!e) { if (state.defeated) drawDefeatOverlay(ctx); return; }
    ctx.save();
    ctx.fillStyle = "rgba(15,23,42,.72)"; ctx.fillRect(150, 22, 660, 112);
    ctx.strokeStyle = "rgba(255,255,255,.18)"; ctx.strokeRect(150, 22, 660, 112);
    ctx.fillStyle = "#fff"; ctx.font = "18px system-ui";
    if (e.type === "trap" && e.phase === "escape") ctx.fillText("ROOT ENCOUNTER — tap Jump / Atk / Dash to escape", 175, 52);
    else if (e.type === "trap") ctx.fillText("LATE HOLD PLACEHOLDER — keep tapping to break out", 175, 52);
    else ctx.fillText("HEALTH-STATE ENCOUNTER — mash to recover", 175, 52);
    drawProgress(ctx, e.progress, e.required, 175, 68);
    ctx.fillStyle = "#cbd5e1"; ctx.font = "14px system-ui";
    const label = e.type === "enemy" ? "Recover" : e.phase === "escape" ? `Escape   Next layer: ${Math.max(0, e.layerTimer).toFixed(1)}s` : "Breakout   Health drains slowly";
    ctx.fillText(`${label} ${e.progress}/${e.required}`, 175, 105);
    ctx.restore();
  }

  function drawDefeatOverlay(ctx) {
    ctx.save();
    ctx.fillStyle = "rgba(15,23,42,.76)"; ctx.fillRect(150, 22, 660, 110);
    ctx.strokeStyle = "rgba(255,255,255,.18)"; ctx.strokeRect(150, 22, 660, 110);
    ctx.fillStyle = "#fff"; ctx.font = "18px system-ui"; ctx.fillText("DEFEAT LOOP PLACEHOLDER", 175, 54);
    ctx.fillStyle = "#cbd5e1"; ctx.font = "14px system-ui"; ctx.fillText("Field remains active. Use Restart or Hub when ready.", 175, 84);
    ctx.fillText(`Loop cycle: ${state.defeatLoop?.cycle ?? 1}`, 175, 108);
    ctx.restore();
  }

  function drawBossDefeatOverlay(ctx) {
    ctx.save();
    ctx.fillStyle = "rgba(15,23,42,.76)"; ctx.fillRect(150, 22, 660, 92);
    ctx.strokeStyle = "rgba(255,255,255,.18)"; ctx.strokeRect(150, 22, 660, 92);
    ctx.fillStyle = "#fff"; ctx.font = "18px system-ui"; ctx.fillText("BOSS DEFEAT PLACEHOLDER", 175, 54);
    ctx.fillStyle = "#cbd5e1"; ctx.font = "14px system-ui"; ctx.fillText("King Slime remains action-only. Restart Boss or return to Hub.", 175, 84);
    ctx.restore();
  }

  function drawProgress(ctx, value, max, x, y) {
    ctx.fillStyle = "#374151"; ctx.fillRect(x, y, 420, 18);
    ctx.fillStyle = C.slime; ctx.fillRect(x, y, 420 * (value / max), 18);
    ctx.strokeStyle = "rgba(255,255,255,.28)"; ctx.strokeRect(x, y, 420, 18);
  }

  function drawKingSlime(ctx, b, time) {
    const hit = b.hitFlash > 0;
    const wobble = Math.sin(time * 5) * 6;
    ctx.save(); ctx.translate(b.x + b.w / 2, b.y + b.h);
    const g = ctx.createRadialGradient(-20, -64, 16, 0, -42, 96);
    g.addColorStop(0, hit ? "#fef3c7" : "#f0abfc"); g.addColorStop(0.4, hit ? "#fbbf24" : C.boss); g.addColorStop(1, C.bossDark);
    ctx.fillStyle = g; ctx.beginPath(); ctx.moveTo(-66, 0); ctx.quadraticCurveTo(-70, -64 + wobble, -8, -92); ctx.quadraticCurveTo(54, -72 - wobble, 66, 0); ctx.quadraticCurveTo(22, 15, -66, 0); ctx.closePath(); ctx.fill();
    ctx.fillStyle = C.white; ctx.fillRect(-24, -54, 8, 8); ctx.fillRect(18, -54, 8, 8);
    ctx.fillStyle = C.trim; ctx.beginPath(); ctx.moveTo(-24, -82); ctx.lineTo(-10, -106); ctx.lineTo(2, -86); ctx.lineTo(18, -108); ctx.lineTo(28, -79); ctx.closePath(); ctx.fill();
    ctx.restore();
  }

  function drawSlamWarning(ctx, zone, time) {
    ctx.fillStyle = "rgba(251,113,133,.16)"; ctx.fillRect(zone.x, zone.y, zone.w, zone.h);
    ctx.strokeStyle = "rgba(251,113,133,.65)"; ctx.lineWidth = 3; ctx.beginPath(); ctx.ellipse(zone.x + zone.w / 2, zone.y + zone.h / 2, zone.w / 2, 24 + Math.sin(time * 18) * 4, 0, 0, Math.PI * 2); ctx.stroke();
  }

  function drawSlamActive(ctx, zone, time) {
    ctx.fillStyle = "rgba(251,113,133,.32)"; ctx.fillRect(zone.x, zone.y, zone.w, zone.h);
    ctx.fillStyle = "rgba(255,255,255,.28)"; ctx.beginPath(); ctx.ellipse(zone.x + zone.w / 2, zone.y + zone.h / 2, zone.w / 2, 22 + Math.sin(time * 40) * 2, 0, 0, Math.PI * 2); ctx.fill();
  }

  function drawGlobCharge(ctx, b, time) {
    const r = 18 + Math.sin(time * 18) * 4;
    ctx.fillStyle = "rgba(192,132,252,.2)"; ctx.beginPath(); ctx.arc(b.x + b.w / 2, b.y + 50, r + 18, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = "rgba(52,211,153,.72)"; ctx.beginPath(); ctx.arc(b.x + b.w / 2, b.y + 50, r, 0, Math.PI * 2); ctx.fill();
  }

  function drawProjectile(ctx, p, time) {
    ctx.fillStyle = "rgba(52,211,153,.18)"; ctx.beginPath(); ctx.arc(p.x, p.y, 25, 0, Math.PI * 2); ctx.fill();
    ctx.fillStyle = C.slime; ctx.beginPath(); ctx.arc(p.x, p.y, 12 + Math.sin(time * 12) * 1.5, 0, Math.PI * 2); ctx.fill();
  }

  function drawHitbox(ctx, actor, cam) {
    if (!actor) return;
    ctx.save(); ctx.strokeStyle = "rgba(56,189,248,.18)"; ctx.lineWidth = 1; ctx.strokeRect(actor.x - cam, actor.y, actor.w, actor.h); ctx.restore();
  }

  function rectsOverlap(a, b) { return a.x < b.x + b.w && a.x + a.w > b.x && a.y < b.y + b.h && a.y + a.h > b.y; }
  function centerX(rect) { return rect.x + rect.w / 2; }
  function distance(x1, y1, x2, y2) { return Math.hypot(x1 - x2, y1 - y2); }
  function clamp(v, min, max) { return Math.max(min, Math.min(max, v)); }
  function randomRange(min, max) { return min + Math.random() * (max - min); }
})();
